"use client";

import { useEffect, useEffectEvent, useRef, useState } from "react";
import { authService } from "@/services/auth.service";
import type { AuthSignInInput, AuthUserState } from "@/types/auth";

// Estado inicial para cuando aún no se ha resuelto el estado de autenticación
const emptyAuthUser: AuthUserState = {
  user: null,
  organizacionId: null,
  rol: null,
  cargando: true,
};
// Estado para usuarios no autenticados
const unauthenticatedState: AuthUserState = {
  user: null,
  organizacionId: null,
  rol: null,
  cargando: false,
};
// Cache para el estado de autenticación y la promesa de resolución
let authStateCache: AuthUserState | null = null;
let authStatePromise: Promise<AuthUserState> | null = null;

// Función para resolver el estado de autenticación, utilizando cache y evitando múltiples llamadas simultáneas
async function resolveAuthState() {
  if (authStateCache && !authStateCache.cargando) {
    return authStateCache;
  }

  if (!authStatePromise) {
    authStatePromise = authService
      .getCurrentAuthState()
      .then((currentAuth) => ({
        ...currentAuth,
        cargando: false,
      }))
      .catch(() => unauthenticatedState)
      .finally(() => {
        authStatePromise = null;
      });
  }

  const nextState = await authStatePromise;
  authStateCache = nextState;

  return nextState;
}

export function useAuth() {
  const [authUser, setAuthUser] = useState<AuthUserState>(authStateCache ?? emptyAuthUser);
  const isMountedRef = useRef(false);

  const syncAuthUser = useEffectEvent(async () => {
    const currentAuth = await resolveAuthState();

    if (isMountedRef.current) {
      setAuthUser(currentAuth);
    }
  });

  useEffect(() => {
    isMountedRef.current = true;

    void syncAuthUser();

    const unsubscribe = authService.subscribeToAuthChanges(() => {
      authStateCache = null;
      void syncAuthUser();
    });

    return () => {
      isMountedRef.current = false;
      unsubscribe();
    };
  }, []);

  const signIn = async (credentials: AuthSignInInput) => {
    await authService.signIn(credentials);
    authStateCache = null;
  };

  const signOut = async () => {
    await authService.signOut();
    authStateCache = unauthenticatedState;
    setAuthUser(unauthenticatedState);
  };

  return {
    ...authUser,
    signIn,
    signOut,
  };
}
